var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 현실 전초기지, <color=#ffd34c>쉘터 No.72</color>\\n관리국 제4 수색전대 <color=#ffd34c>야크샤</color> 임시 본부","JPN":"管理局現実前哨基地、<color=#ffd34c>シェルターNo.72</color>\\n管理局第4捜索戦隊<color=#ffd34c>ヤクシャー</color>臨時本部","ENG":"[[","TWN":"管理局現世前哨站，<color=#ffd34c>72號庇護所</color>\\n管理局第4偵察戰隊<color=#ffd34c>夜叉</color>臨時總部","SCN":"管理局现世前哨站，<color=#ffd34c>72号庇护所</color>\\n管理局第4侦察战队<color=#ffd34c>夜叉</color>临时总部","DEU":"[[","FRA":"[["},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"아야야……! 너무 세게 묶는 거 아니야? 살살 좀 하라고!","JPN":"いたた……！　強く縛りすぎだぞ！　手加減しろよ！","ENG":"Oww...! Don't you think you're tying me up too tight? Be gentle!","TWN":"嗷……！你是不是綁得太緊了？輕一點！"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"}}}},{"id":"L7_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"후후, 보기보다 엄살이 심하구나?","JPN":"ふふ、大げさね。","ENG":"Fu fuu, didn't take you for a crybaby.","TWN":"呵呵，你很會裝嘛？"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"}}}},{"id":"L8_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"다행히 상처가 침식파에 오염되지는 않았어. 몸이 튼튼해서 다행이네.","JPN":"幸い、傷口も侵食波に汚染されてない。丈夫な体でよかったね。","ENG":"Luckily, your wound isn't contaminated by the Corruption ray. Thank goodness your body's strong.","TWN":"幸好傷口沒有被侵蝕波感染。多虧了你這副強壯的身體。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"}}}},{"id":"L9_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"4종 정도 되는 침식체에게 입은 부상은 아무리 가벼운 상처라도 얕볼 수 없거든.","JPN":"第4種くらいの侵食体にやられた傷はどんなに小さくても注意が必要よ。","ENG":"Any wound from a Category 4 C.O. cannot be underestimated, no matter how light it is.","TWN":"不要小看4類侵蝕體造成的傷口，無論傷口有多小。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"}}}},{"id":"L10_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"으음? 표정이 왜 그래? 괜찮아, 앨리스?","JPN":"ん？　どうしたの？　大丈夫、アリス？","ENG":"Hmm? What's wrong? Are you okay, Alice?","TWN":"嗯？你那是什麼表情？你還好嗎，艾莉絲？"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"아직 어디 아픈 데라도 있어?","JPN":"まだどこか痛むところがあるの？","ENG":"Does it still hurt somewhere?","TWN":"還有什麼地方痛嗎？"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"……이젠 길고양이라고 안 부르네?","JPN":"……もう、野良猫って呼ばないんだな。","ENG":"...You're not calling me stray cat anymore.","TWN":"……你不叫我流浪貓了嗎？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"……음?","JPN":"……ん？","ENG":"...Hmm?","TWN":"……嗯？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"후후, 뭐야~? 안 그런 척하더니, 계속 신경 쓰고 있었던 거야~?","JPN":"ふふ、なぁに～？　意外ね。そんなこと気にしてたの？","ENG":"Fu fuu, is that it? I didn't think you cared, but did you?","TWN":"呵呵，什麼啊～？原來你在意啊～"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그, 그런 거 아니거든!?","JPN":"そ、そうじゃない！","ENG":"N-no, I wasn't!","TWN":"才、才不是那樣？！"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"돌아올 곳이 있고, 널 기다리는 사람들이 있는데……. 네가 왜 길고양이겠어.","JPN":"帰る場所があって、あなたを待ってる人たちがいるのに……あなたが野良猫なわけないでしょ。","ENG":"You have a home, and people waiting for you to come back... You're not a stray cat.","TWN":"你有家可回，還有人在等你……你怎麼會是流浪貓呢？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"넌 결국 훌륭하게 스스로 그림자를 끊어냈잖아?","JPN":"あなたは結局、自分で見事シャドウを断ち切ったじゃない。","ENG":"Plus, you defeated your own Shadow with excellence, no?","TWN":"最後，你自己成功斬斷了暗影吧？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그러니 이제부터 넌 야크샤의 일원이자, 우리의 가족이야.","JPN":"だから、これからあなたはヤクシャーの一員で、私たちの家族よ。","ENG":"Now, you're a member of the Yaksha Division, and also our family.","TWN":"所以從現在開始，你不僅是夜叉的一員，也是我們這個大家庭的一員了。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"네가 도와준 거잖아? 그걸로 괜찮아?","JPN":"でも、お前に手伝ってもらったじゃないか。それでもいいのか？","ENG":"But you helped me. Is that okay?","TWN":"但那是你幫了我啊？這也沒關係嗎？"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"물론이지, 각오를 보여준 것만으로도 충분해.","JPN":"もちろん、覚悟を見せてくれただけで十分よ。","ENG":"Of course. Just showing your determination is enough.","TWN":"當然，只要表現出決心就足夠了。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"쥐스틴도 펑펑 울었지만 결국 해냈거든.","JPN":"ジュスティーヌもわんわん泣いてたけど結局やってのけたしね。","ENG":"Justine cried the whole way, but she also did it.","TWN":"潔絲婷當時也哇哇哭得很慘，但最後也做到了。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"참나, 그 완두콩이랑 비교하니까 갑자기 맥 빠지네.","JPN":"ったく、あのちんちくりんと比べられると拍子抜けするな。","ENG":"Ugh, comparing me to green pea kinda ruined it.","TWN":"呃，你要是拿我和那顆豌豆比的話，我可就要生氣了。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_PRIDE"}}}},{"id":"L31_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"후후, 그래도 고생했어, 앨리스.","JPN":"ふふ、でも本当にお疲れ様、アリス。","ENG":"Fu fuu, but still. Great work, Alice.","TWN":"呵呵，總之，辛苦你了，艾莉絲。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_PRIDE"}}}},{"id":"L33_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"흐음~ 하지만 애칭이 없어진 건, 살짝 서운할지도~?","JPN":"うーん、でもやっぱりあだ名がなくなっちゃったのはちょっと寂しいかな。","ENG":"Hmm... But not calling you by a nickname is kind of sad, don't you think?","TWN":"嗯……不過不能叫你的外號，總覺得有些失落呢～？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"역시 검은 고양이니까, 네로 어떨까?","JPN":"そうねえ、黒い猫だから「ネロ」とかはどう？","ENG":"Since you're a black cat, how does Nero sound?","TWN":"畢竟是隻黑貓，不如叫諭吉吧？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"구려.","JPN":"ダサい。","ENG":"Terrible.","TWN":"討厭。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"후후. 딱 잘라서 거절하다니, 너무하네.","JPN":"ふふ、そんなに即答で断らなくてもいいじゃない。","ENG":"Fu fuu. Ouch. You didn't have to reject it so harshly.","TWN":"哎呀？拒絕得這麼乾脆，真是過分。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};